	            const blob = Buffer.allocUnsafe(4 + sessionID.length + blobEnd);
	            writeUInt32BE(blob, sessionID.length, 0);
	            blob.set(sessionID, 4);
	            blob.set(
	              new Uint8Array(payload.buffer, payload.byteOffset, blobEnd),
	              4 + sessionID.length
	            );
